# 1. Get the OIDC issuer URL for your EKS cluster
EKS_CLUSTER_NAME=my-agent-cluster
OIDC_ISSUER=$(aws eks describe-cluster \
  --name $EKS_CLUSTER_NAME \
  --query 'cluster.identity.oidc.issuer' \
  --output text)
echo "OIDC Issuer: $OIDC_ISSUER"

# 2. Create an IAM OIDC provider for the cluster (one-time setup)
eksctl utils associate-iam-oidc-provider \
  --cluster $EKS_CLUSTER_NAME \
  --approve

# 3. Create an IAM role that trusts the K8s ServiceAccount via OIDC
cat > trust-policy.json << EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Federated": "arn:aws:iam::${AWS_ACCOUNT_ID}:oidc-provider/${OIDC_ISSUER#https://}"
      },
      "Action": "sts:AssumeRoleWithWebIdentity",
      "Condition": {
        "StringEquals": {
          "${OIDC_ISSUER#https://}:sub": "system:serviceaccount:agents:research-agent",
          "${OIDC_ISSUER#https://}:aud": "sts.amazonaws.com"
        }
      }
    }
  ]
}
EOF

aws iam create-role \
  --role-name agent-research-role \
  --assume-role-policy-document file://trust-policy.json

# 4. Attach a least-privilege policy
aws iam put-role-policy \
  --role-name agent-research-role \
  --policy-name research-agent-policy \
  --policy-document '{
    "Version": "2012-10-17",
    "Statement": [
      {
        "Effect": "Allow",
        "Action": ["s3:GetObject"],
        "Resource": "arn:aws:s3:::agent-documents/*"
      },
      {
        "Effect": "Allow",
        "Action": ["secretsmanager:GetSecretValue"],
        "Resource": "arn:aws:secretsmanager:*:*:secret:agents/research/*"
      }
    ]
  }'

# 5. Annotate the Kubernetes ServiceAccount with the IAM role ARN
kubectl annotate serviceaccount \
  -n agents \
  research-agent \
  eks.amazonaws.com/role-arn=arn:aws:iam::${AWS_ACCOUNT_ID}:role/agent-research-role

# policy/agent_access.rego
# OPA policy controlling which agents may call which tools,
# conditioned on the user's role that triggered the agent.

package agent.access

import future.keywords.in

# Default to deny — explicit allow rules must match
default allow = false

# Agent may call a tool if it is in the allow-list for that agent type
allow if {
    # input.principal = SPIFFE URI of the calling agent
    # input.tool      = the tool being requested (e.g., "web_search")
    # input.user_role = the role of the human who triggered the agent
    agent_tool_allowed
    user_role_permitted
}

# Define which tools each agent SPIFFE identity may use
agent_tool_matrix := {
    "spiffe://cluster.local/ns/agents/sa/research-agent": [
        "web_search", "document_read", "vector_db_query"
    ],
    "spiffe://cluster.local/ns/agents/sa/code-agent": [
        "code_execute", "file_read", "file_write"
    ],
    "spiffe://cluster.local/ns/agents/sa/orchestrator-agent": [
        "web_search", "document_read", "vector_db_query",
        "code_execute", "email_send"
    ],
}

agent_tool_allowed if {
    allowed_tools := agent_tool_matrix[input.principal]
    input.tool in allowed_tools
}

# user role → permitted tool categories
user_role_permitted if {
    # Standard users may not use code execution tools
    not startswith(input.tool, "code_")
}

user_role_permitted if {
    # Developers and admins may trigger code execution
    input.user_role in {"developer", "admin"}
    startswith(input.tool, "code_")
}

# Deny email sending outside business hours (UTC)
user_role_permitted if {
    input.tool == "email_send"
    input.user_role == "admin"  # only admins may send email at any time
}

# Reasons for denial (returned in the decision log)
deny_reason := msg if {
    not agent_tool_allowed
    msg := sprintf("Agent %v is not permitted to use tool %v", [input.principal, input.tool])
}

deny_reason := msg if {
    agent_tool_allowed
    not user_role_permitted
    msg := sprintf("User role %v is not permitted to trigger tool %v", [input.user_role, input.tool])
}
